wifi = pd.DataFrame(var_call_8QMpACnxEvBQ0302SJHJ4jy7)
rev = pd.DataFrame(var_call_eMNzsA0X1lRWuMbdH0oy8y0P)

def extract_state(desc):
    if not isinstance(desc, str):
        return None
    m = re.search(r"\bin\s+[^,]+,\s*([A-Z]{2})\b", desc)
    if m:
        return m.group(1)
    return None

wifi['state'] = wifi['description'].map(extract_state)
wifi = wifi.dropna(subset=['state'])

if wifi.empty:
    out = {'error':'No WiFi businesses with parsable US state found in description.'}
    print('__RESULT__:')
    print(json.dumps(out))
else:
    state_counts = wifi.groupby('state', as_index=False).agg(wifi_business_count=('business_id','nunique'))
    state_counts = state_counts.sort_values(['wifi_business_count','state'], ascending=[False, True])
    top_state = state_counts.iloc[0]['state']

    wifi['business_ref'] = wifi['business_id'].str.replace('businessid_', 'businessref_', regex=False)
    wifi_top = wifi[wifi['state']==top_state][['business_ref']].drop_duplicates()
    merged = wifi_top.merge(rev, on='business_ref', how='left')
    if 'avg_rating' in merged.columns:
        merged['avg_rating'] = pd.to_numeric(merged['avg_rating'], errors='coerce')
        state_avg_rating = merged['avg_rating'].mean()
    else:
        state_avg_rating = float('nan')

    out = {
        'state': top_state,
        'wifi_business_count': int(state_counts.iloc[0]['wifi_business_count']),
        'average_rating_for_wifi_businesses_in_state': None if pd.isna(state_avg_rating) else float(state_avg_rating)
    }
    print('__RESULT__:')
    print(json.dumps(out))"}

